        public void PDFCompare()
        {
         //   string exePath = @"C:\Program Files\diffpdfc\diffpdfc.exe";
         	string exePath = @"C:\pdfcompare\comparepdf-1.0.0-win32-static\comparepdf.exe";
         //   string arguments = "-q \"" + ReferencePath + "\" \"" + OutputPath + "\" -r \"" + PDFCompareResultFilePath  + "\" -a -A 80";
           
            
            
         /*   if (System.IO.File.Exists(PDFCompareResultFilePath))
