            var RefPathDir = new DirectoryInfo(ReferencePath).GetFiles("*.pdf").Select(o => o.Name).ToList<string>();           
            var OutputPathDir = new DirectoryInfo(OutputPath).GetFiles("*.pdf").Select(o => o.Name).ToList<string>();
            var ListtoCompare = RefPathDir.Intersect(OutputPathDir);
            foreach (var item in ListtoCompare) 
            {
            	var newRefPath = ReferencePath + "\\" + item;
            	var newOutputPath = OutputPath + "\\" + item;
            	string arguments = "-ca \"" + newRefPath + "\" \"" + newOutputPath + "\"";
            	Report.Log(ReportLevel.Info,"Running PDF Compare with arguments: " + arguments);
            	var messages = runProcess(exePath, arguments);
	            if (messages.Contains("Files look different."))
	            {
	                Report.Warn("Potential differences detected, please check both files!");
	            }
	            else if (messages.IsEmpty() || messages == null)
	            {
	                Report.Success("Files have the same appearance");                
	            }
            	
	            else
	            {
	            	Report.Log(ReportLevel.Error,"Error from pdfcompare: " + messages);
	            }
	            
            }
            
        }

        private static string runProcess(string applicationPath, string inputString)
        {
            using (System.Diagnostics.Process p = new System.Diagnostics.Process())
            {
                p.StartInfo.UseShellExecute = false;
                p.StartInfo.RedirectStandardOutput = true;
                p.StartInfo.FileName = applicationPath;
                p.StartInfo.Arguments = inputString;
                p.Start();
                string messages = p.StandardOutput.ReadToEnd();
                p.WaitForExit(30000);
                Report.Log(ReportLevel.Info, messages);
                return messages;
               
            }            
        }
